To develop a Checkers (Draughts) game in Python, we'll need to create a few classes and methods:

1. `Board`: Represents the checkers board with 8x8 squares.
2. `Piece`: Represents a piece on the board, which can be either a normal piece or a king.
3. `Game`: Manages the game state, including player turns and move validation.

Let's start by implementing these classes and methods step-by-step.

### Step 1: Define the Board Class

```python
class Board:
    def __init__(self):
        self.board = [[None for _ in range(8)] for _ in range(8)]
        self.initialize_board()

    def initialize_board(self):
        pieces = ['r', 'b']  # Red and Black pieces
        for row in range(3):
            for col in range(0, 8, 2):
                if (row + col) % 2 == 1:
                    self.board[row][col] = Piece(pieces[0], (row, col))
        for row in range(5, 8):
            for col in range(0, 8, 2):
                if (row + col) % 2 == 1:
                    self.board[row][col] = Piece(pieces[1], (row, col))

    def print_board(self):
        for row in self.board:
            print(" ".join([str(piece) if piece else "." for piece in row]))

class Piece:
    def __init__(self, color, position):
        self.color = color
        self.position = position
        self.king = False

    def __str__(self):
        return self.color.upper() + ('K' if self.king else '')

    def move(self, new_position):
        self.position = new_position
        if (new_position[0] == 0 and self.color == 'r') or (new_position[0] == 7 and self.color == 'b'):
            self.king = True

# Example usage
board = Board()
board.print_board()
```

### Step 2: Define the Game Class

```python
class Game:
    def __init__(self):
        self.board = Board()
        self.current_player = 'r'

    def print_board(self):
        self.board.print_board()

    def is_valid_move(self, from_pos, to_pos):
        piece = self.board.board[from_pos[0]][from_pos[1]]
        if piece and piece.color == self.current_player:
            # Check if the move is valid
            return True
        return False

    def make_move(self, from_pos, to_pos):
        if self.is_valid_move(from_pos, to_pos):
            piece = self.board.board[from_pos[0]][from_pos[1]]
            piece.move(to_pos)
            self.current_player = 'b' if self.current_player == 'r' else 'r'
            print(f"Move {from_pos} to {to_pos} by {self.current_player}")
        else:
            print("Invalid move. Try again.")

    def check_winner(self):
        # Check for win or draw
        pieces = [piece for row in self.board.board for piece in row if piece and piece.color == 'r']
        if not pieces:
            return 'b'
        pieces = [piece for row in self.board.board for piece in row if piece and piece.color == 'b']
        if not pieces:
            return 'r'
        return None

# Example usage
game = Game()
game.print_board()
while True:
    move_from = input(f"Player {game.current_player}, enter your move (from-to): ").split('-')
    game.make_move((int(move_from[0][1]), int(move_from[0][3])), (int(move_from[1][1]), int(move_from[1][3])))
    game.print_board()
    winner = game.check_winner()
    if winner:
        print(f"Player {winner} wins!")
        break
```

### Step 3: Implement Additional Features

To make the game more complete, we need to handle captures and kinging:

