class Board:
    def move_piece(self, from_pos, to_pos):
        piece = self.board[from_pos[0]][from_pos[1]]
        piece.move(to_pos)
        if (to_pos[0] == 0 and piece.color == 'r') or (to_pos[0] == 7 and piece.color == 'b'):
            piece.king = True

    def capture_piece(self, from_pos, to_pos):
        mid_pos = ((from_pos[0] + to_pos[0]) // 2, (from_pos[1] + to_pos[1]) // 2)
        self.board[mid_pos[0]][mid_pos[1]] = None
        self.move_piece(from_pos, to_pos)

    def is_capture_possible(self, from_pos):
        piece = self.board[from_pos[0]][from_pos[1]]
        directions = [(-1, -1), (-1, 1), (1, -1), (1, 1)]
        for direction in directions:
            new_pos = (from_pos[0] + 2 * direction[0], from_pos[1] + 2 * direction[1])
            if 0 <= new_pos[0] < 8 and 0 <= new_pos[1] < 8:
                mid_pos = (from_pos[0] + direction[0], from_pos[1] + direction[1])
                if self.board[mid_pos[0]][mid_pos[1]] and \
                   self.board[mid_pos[0]][mid_pos[1]].color != piece.color and \
                   self.board[new_pos[0]][new_pos[1]] is None:
                    return True
        return False

    def get_valid_moves(self, from_pos):
        moves = []
        directions = [(-1, -1), (-1, 1), (1, -1), (1, 1)]
        for direction in directions:
            new_pos = (from_pos[0] + direction[0], from_pos[1] + direction[1])
            if 0 <= new_pos[0] < 8 and 0 <= new_pos[1] < 8:
                if self.board[new_pos[0]][new_pos[1]] is None:
                    moves.append(new_pos)
                elif self.is_capture_possible(from_pos):
                    mid_pos = (from_pos[0] + direction[0], from_pos[1] + direction[1])
                    new_new_pos = (mid_pos[0] + direction[0], mid_pos[1] + direction[1])
                    if 0 <= new_new_pos[0] < 8 and 0 <= new_new_pos[1] < 8:
                        moves.append(new_new_pos)
        return moves

class Game:
    def is_valid_move(self, from_pos, to_pos):
        piece = self.board.board[from_pos[0]][from_pos[1]]
        if not piece or piece.color != self.current_player:
            return False
        valid_moves = self.board.get_valid_moves(from_pos)
        return to_pos in valid_moves

    def make_move(self, from_pos, to_pos):
        if self.is_valid_move(from_pos, to_pos):
            piece = self.board.board[from_pos[0]][from_pos[1]]
            mid_pos = ((from_pos[0] + to_pos[0]) // 2, (from_pos[1] + to_pos[1]) // 2)
            if self.board.board[mid_pos[0]][mid_pos[1]] and \
               self.board.board[mid_pos[0]][mid_pos[1]].color != piece.color:
                self.board.capture_piece(from_pos, to_pos)
            else:
                self.board.move_piece(from_pos, to_pos)
            self.current_player = 'b' if self.current_player == 'r' else 'r'
        else:
            print("Invalid move. Try again.")

